final:
module RefModule(
    input clk,
    input [3:0] parallel_in,
    input serial_in,
    output serial_out
);reg [3:0] unused_register;

always @(posedge clk) begin
    if (parallel_in) begin
        unused_register <= parallel_in;
    end else begin
        unused_register <= {unused_register[2:0], serial_in};
    end
end

assign serial_out = unused_register[0];

endmodule
